        _handleDeepLink(initialLink);
      }
    } catch (e) {
      setState(() {
        _latestError = e.toString();
      });
    }
  }

  void _handleDeepLink(String link) {
    final uri = Uri.parse(link);

    if (uri.scheme != 'myapp') {
      _showError('Invalid scheme: ${uri.scheme}');
      return;
    }

    final path = uri.host;
    final pathSegments = uri.pathSegments;
    final queryParams = uri.queryParameters;

    switch (path) {
      case 'profile':
        if (pathSegments.isNotEmpty) {
          final userId = pathSegments[0];
          _navigateToProfile(userId, queryParams);
        } else {
          _showError('Profile ID is missing');
        }
        break;

      case 'payment':
        if (pathSegments.isNotEmpty && pathSegments[0] == 'confirm') {
          _navigateToPayment(queryParams);
        } else {
          _showError('Invalid payment path');
        }
        break;

      case 'home':
        _navigateToHome(queryParams);
        break;

      default:
        _showError('Unknown path: $path');
    }
  }

  void _navigateToProfile(String userId, Map<String, String> params) {
    Navigator.pushNamed(
      context,
      '/profile',
      arguments: {
        'userId': userId,
        'params': params,
      },
    );
  }

  void _navigateToPayment(Map<String, String> params) {
    Navigator.pushNamed(
      context,
      '/payment',
      arguments: {
